35	// PodManager Pod 资源管理接口
36	type PodManager interface {
37		// CreatePod 创建 Pod
38		CreatePod(ctx context.Context, pod *PodSpec) error
39		// DeletePod 删除 Pod
40		DeletePod(ctx context.Context, name string) error
41		// GetPod 获取 Pod 信息
