49	func (c *client) CreatePod(ctx context.Context, pod *PodSpec) error {
50		envVars := []corev1.EnvVar{}
51		for k, v := range pod.Env {
52			envVars = append(envVars, corev1.EnvVar{
53				Name:  k,
54				Value: v,
55			})
56		}
57	
58		container := corev1.Container{
59			Name:    pod.Name,
60			Image:   pod.Image,
61			Command: pod.Command,
62			Args:    pod.Args,
63			Env:     envVars,
64		}
65	
66		if pod.Resources != nil {
67			container.Resources = corev1.ResourceRequirements{
68				Requests: corev1.ResourceList{},
69				Limits:   corev1.ResourceList{},
70			}
71			if pod.Resources.CPURequest != "" {
72				container.Resources.Requests[corev1.ResourceCPU] = resource.MustParse(pod.Resources.CPURequest)
73			}
74			if pod.Resources.CPULimit != "" {
75				container.Resources.Limits[corev1.ResourceCPU] = resource.MustParse(pod.Resources.CPULimit)
76			}
77			if pod.Resources.MemoryRequest != "" {
78				container.Resources.Requests[corev1.ResourceMemory] = resource.MustParse(pod.Resources.MemoryRequest)
79			}
80			if pod.Resources.MemoryLimit != "" {
81				container.Resources.Limits[corev1.ResourceMemory] = resource.MustParse(pod.Resources.MemoryLimit)
82			}
83		}
84	
85		k8sPod := &corev1.Pod{
86			ObjectMeta: metav1.ObjectMeta{
87				Name:   pod.Name,
88				Labels: pod.Labels,
89			},
90			Spec: corev1.PodSpec{
91				Containers: []corev1.Container{container},
92			},
93		}
94	
95		_, err := c.clientset.CoreV1().Pods(c.namespace).Create(ctx, k8sPod, metav1.CreateOptions{})
96		return err
97	}
