103	func (c *client) GetPod(ctx context.Context, name string) (*PodInfo, error) {
104		pod, err := c.clientset.CoreV1().Pods(c.namespace).Get(ctx, name, metav1.GetOptions{})
105		if err != nil {
106			return nil, err
107		}
108	
109		image := ""
110		if len(pod.Spec.Containers) > 0 {
111			image = pod.Spec.Containers[0].Image
112		}
113	
114		return &PodInfo{
115			Name:      pod.Name,
116			Status:    string(pod.Status.Phase),
117			Image:     image,
118			CreatedAt: pod.CreationTimestamp.Format("2006-01-02 15:04:05"),
119			Labels:    pod.Labels,
120		}, nil
121	}
