123	func (c *client) ListPods(ctx context.Context, labelMap map[string]string) ([]PodInfo, error) {
124		selector := labels.SelectorFromSet(labelMap)
125		pods, err := c.clientset.CoreV1().Pods(c.namespace).List(ctx, metav1.ListOptions{
126			LabelSelector: selector.String(),
127		})
128		if err != nil {
129			return nil, err
130		}
131	
132		var podInfos []PodInfo
133		for _, pod := range pods.Items {
134			image := ""
135			if len(pod.Spec.Containers) > 0 {
136				image = pod.Spec.Containers[0].Image
137			}
138	
139			podInfos = append(podInfos, PodInfo{
140				Name:      pod.Name,
141				Status:    string(pod.Status.Phase),
142				Image:     image,
143				CreatedAt: pod.CreationTimestamp.Format("2006-01-02 15:04:05"),
144				Labels:    pod.Labels,
145			})
146		}
147	
148		return podInfos, nil
149	}
