151	func (c *client) GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error) {
152		req := c.clientset.CoreV1().Pods(c.namespace).GetLogs(name, &corev1.PodLogOptions{
153			TailLines: &tailLines,
154		})
155	
156		logs, err := req.Stream(ctx)
157		if err != nil {
158			return "", err
159		}
160		defer logs.Close()
161	
162		var logData []byte
163		buf := make([]byte, 1024)
164		for {
165			n, err := logs.Read(buf)
166			if n > 0 {
167				logData = append(logData, buf[:n]...)
168			}
169			if err != nil {
170				break
171			}
172		}
173	
174		return string(logData), nil
175	}
