326	func (s *service) ListDevmachines(ctx context.Context, devmachines []devmachinemodel.DevmachineName) ([]devmachinemodel.Devmachine, error) {
327		// 如果没有指定任何devmachine，则返回空列表
328		if len(devmachines) == 0 {
329			return []devmachinemodel.Devmachine{}, nil
330		}
331	
332		// 初始化结果切片
333		results := make([]devmachinemodel.Devmachine, len(devmachines))
334		errors := make([]error, len(devmachines))
335	
336		// 定义工作函数
337		workerFunc := func(piece int) {
338			// 获取指定的devmachine
339			devmachine := devmachines[piece]
340			// 调用GetDevmachine获取详细信息
341			result, err := s.GetDevmachine(ctx, devmachine.Namespace, devmachine.Name)
342			if err != nil {
343				errors[piece] = err
344			} else {
345				results[piece] = result.Devmachine
346			}
347		}
348	
349		// 使用workqueue.ParallelizeUntil进行并行处理
350		// 限制最大并发数以避免对k8s API服务器造成过大压力
351		maxWorkers := 10
352		workqueue.ParallelizeUntil(ctx, maxWorkers, len(devmachines), workerFunc)
353	
354		// 收集成功的结果
355		var successfulResults []devmachinemodel.Devmachine
356		for i, err := range errors {
357			if err == nil {
358				successfulResults = append(successfulResults, results[i])
359			} else {
360				log.Printf("warning: failed to get devmachine %s/%s: %v", devmachines[i].Namespace, devmachines[i].Name, err)
361			}
362		}
363	
364		return successfulResults, nil
365	}
