367	func (s *service) StartDevmachine(ctx context.Context, namespace, name string) error {
368		// 验证请求参数
369		if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
370			return NewValidationError("devmachine", name, err)
