372	
373		// 获取 Deployment
374		deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
375		if err != nil {
376			return NewResourceError("Deployment", name, "get", err)
377		}
378	
379		// 设置 replicas 为 1
380		deployment.Spec.Replicas = ptr.To[int32](1)
381	
382		// 更新 Deployment
383		if err := s.k8sClient.UpdateDeployment(ctx, deployment); err != nil {
