393	// BuildResourceRequirements 构建资源请求和限制
394	func BuildResourceRequirements(cpu, memory, gpu, gpuName string) corev1.ResourceRequirements {
395		requests := corev1.ResourceList{}
396		limits := corev1.ResourceList{}
397	
398		// 设置 CPU 请求
399		if cpu != "" {
400			cpuQuantity, err := resource.ParseQuantity(cpu + "") // 用户传入的数值，单位为核
401			if err == nil {
402				requests[corev1.ResourceCPU] = cpuQuantity
403				limits[corev1.ResourceCPU] = cpuQuantity
404			}
405		}
406	
407		// 设置内存请求
408		if memory != "" {
409			memoryQuantity, err := resource.ParseQuantity(memory + "Gi") // 用户传入的数值，单位为Gi
410			if err == nil {
411				requests[corev1.ResourceMemory] = memoryQuantity
412				limits[corev1.ResourceMemory] = memoryQuantity
413			}
414		}
415	
416		// 设置 GPU 请求
417		if gpu != "" && gpuName != "" {
418			gpuQuantity, err := resource.ParseQuantity(gpu) // GPU 数量
419			if err == nil {
420				// 检查 GPU 是否为虚拟化类型
421				if resourcesvc.IsGPUResource(gpuName) && resourcesvc.GetGPUType(gpuName) == resourcesvc.GPUCardTypeVirtual {
422					// 如果是虚拟化 GPU，需要特殊处理
423					requests[corev1.ResourceName(gpuName)] = gpuQuantity
424					limits[corev1.ResourceName(gpuName)] = gpuQuantity
425					//
426	
427				} else {
428					// 如果是整卡 GPU，直接设置
429					requests[corev1.ResourceName(gpuName)] = gpuQuantity
430					limits[corev1.ResourceName(gpuName)] = gpuQuantity
431				}
432			}
433		}
434	
435		return corev1.ResourceRequirements{
436			Requests: requests,
